//! Raw FFI bindings to PTX-OS GPU runtime and CUDA libraries.
//!
//! This crate provides unsafe bindings generated by bindgen from the PTX-OS headers.
//! For safe wrappers, use the `ptx-runtime` crate.
//!
//! # Safety
//!
//! All functions in this crate are unsafe. The caller must ensure:
//! - Valid pointers are passed
//! - Proper synchronization for concurrent access
//! - Memory is properly allocated via PTX-OS allocator

#![allow(non_upper_case_globals)]
#![allow(non_camel_case_types)]
#![allow(non_snake_case)]
#![allow(dead_code)]
#![allow(clippy::all)]

use libc::{c_char, c_int, c_uint, c_void, size_t, ssize_t};

// CUDA types as opaque pointers
pub type cudaStream_t = *mut c_void;
pub type cudaGraph_t = *mut c_void;
pub type cudaGraphExec_t = *mut c_void;
pub type cudaError_t = c_int;
pub type cudaGraphicsResource_t = *mut c_void;

// CUDA driver API context handle
pub type CUcontext = *mut c_void;

// dim3 struct for kernel launch configuration
#[repr(C)]
#[derive(Debug, Copy, Clone, Default)]
pub struct dim3 {
    pub x: u32,
    pub y: u32,
    pub z: u32,
}

impl dim3 {
    pub fn new(x: u32, y: u32, z: u32) -> Self {
        Self { x, y, z }
    }
}

// CUDA IPC memory handle
#[repr(C)]
#[derive(Debug, Copy, Clone)]
pub struct cudaIpcMemHandle_t {
    pub reserved: [c_char; 64],
}

impl Default for cudaIpcMemHandle_t {
    fn default() -> Self {
        Self { reserved: [0; 64] }
    }
}

// Half precision type placeholder
#[repr(C)]
#[derive(Debug, Copy, Clone, Default)]
pub struct __half {
    pub x: u16,
}

// Type aliases for convenience
pub type DType = PTXDType;
pub type OpCode = PTXTensorOpcode;

