// ============================================================================
// Tensor Opcodes
// ============================================================================

#[repr(u32)]
#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash, Default)]
pub enum PTXTensorOpcode {
    // Binary Operations (0x10 - 0x1F)
    #[default]
    Add = 0x10,
    Sub = 0x11,
    Mul = 0x12,
    Div = 0x13,
    Max = 0x14,
    Min = 0x15,
    Pow = 0x16,
    Mod = 0x17,

    // Unary Operations (0x20 - 0x3F)
    Neg = 0x20,
    Abs = 0x21,
    Exp = 0x22,
    Log = 0x23,
    Log2 = 0x24,
    Log10 = 0x25,
    Sqrt = 0x26,
    Rsqrt = 0x27,
    Sin = 0x28,
    Cos = 0x29,
    Tan = 0x2A,
    Tanh = 0x2B,
    Sinh = 0x2C,
    Cosh = 0x2D,
    Ceil = 0x2E,
    Floor = 0x2F,
    Round = 0x30,
    Sign = 0x31,
    Recip = 0x32,
    Sqr = 0x33,
    Erf = 0x34,

    // Activation Functions (0x40 - 0x4F)
    Relu = 0x40,
    Relu6 = 0x41,
    LeakyRelu = 0x42,
    Elu = 0x43,
    Selu = 0x44,
    Gelu = 0x45,
    GeluTanh = 0x46,
    Sigmoid = 0x47,
    Silu = 0x48,
    Softplus = 0x49,
    Mish = 0x4A,
    HardSwish = 0x4B,
    HardSigmoid = 0x4C,

    // Reduction Operations (0x50 - 0x5F)
    ReduceSum = 0x50,
    ReduceMean = 0x51,
    ReduceMax = 0x52,
    ReduceMin = 0x53,
    ReduceProd = 0x54,
    ReduceArgmax = 0x55,
    ReduceArgmin = 0x56,

    // Softmax Operations (0x60 - 0x6F)
    Softmax = 0x60,
    LogSoftmax = 0x61,

    // Comparison Operations (0x70 - 0x7F)
    CmpEq = 0x70,
    CmpNe = 0x71,
    CmpLt = 0x72,
    CmpLe = 0x73,
    CmpGt = 0x74,
    CmpGe = 0x75,

    // Affine/Transform Operations (0x80 - 0x8F)
    Affine = 0x80,
    Clamp = 0x81,
    Where = 0x82,

    // Copy Operations (0x90 - 0x9F)
    Copy = 0x90,
    Cast = 0x91,
    Fill = 0x92,

    // Gather/Scatter Operations (0xB0 - 0xB5)
    Gather = 0xB0,
    ScatterAdd = 0xB1,
    IndexSelect = 0xB2,
    IndexAdd = 0xB3,

    // Scan/Prefix Operations (0xC0 - 0xC5)
    CumSum = 0xC0,

    // Sort/Select Operations (0xE0 - 0xEF)
    Argsort = 0xE1,
    TopK = 0xE2,
}

// ============================================================================
// Data Types
// ============================================================================

#[repr(u32)]
#[derive(Debug, Copy, Clone, PartialEq, Eq, Hash, Default)]
pub enum PTXDType {
    #[default]
    F32 = 0,
    F64 = 1,
    F16 = 2,
    BF16 = 3,
    I8 = 4,
    I16 = 5,
    I32 = 6,
    I64 = 7,
    U8 = 8,
    U32 = 9,
}

impl PTXDType {
    /// Size in bytes
    pub const fn size_bytes(&self) -> usize {
        match self {
            PTXDType::F32 => 4,
            PTXDType::F64 => 8,
            PTXDType::F16 => 2,
            PTXDType::BF16 => 2,
            PTXDType::I8 => 1,
            PTXDType::I16 => 2,
            PTXDType::I32 => 4,
            PTXDType::I64 => 8,
            PTXDType::U8 => 1,
            PTXDType::U32 => 4,
        }
    }
}

